/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_funcao_imagem_pos_pendente` AFTER UPDATE ON `funcao_imagem` FOR EACH ROW BEGIN
  
  IF NEW.funcao_id = 5
     AND (NEW.status = 'Aprovado' OR NEW.status = 'Finalizado')
     AND (OLD.status IS NULL OR (OLD.status <> 'Aprovado' AND OLD.status <> 'Finalizado')) THEN

    INSERT INTO postagem_pendentes (imagem_id, funcao_imagem_id, status_id)
    VALUES (
      NEW.imagem_id,
      NEW.idfuncao_imagem,
      (SELECT i.status_id FROM imagens_cliente_obra i WHERE i.idimagens_cliente_obra = NEW.imagem_id LIMIT 1)
    )
    ON DUPLICATE KEY UPDATE criado_em = criado_em; 
  END IF;
END */;;
