/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `log_alteracoes_trigger` AFTER UPDATE ON `funcao_imagem` FOR EACH ROW BEGIN
    IF OLD.status != NEW.status THEN
        INSERT INTO log_alteracoes (
            funcao_imagem_id,
            status_anterior,
            status_novo,
            data,
            colaborador_id
        ) VALUES (
            NEW.idfuncao_imagem,
            OLD.status,
            NEW.status,
            NOW(),
            NEW.colaborador_id
        );
    END IF;
END */;;
