/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_funcao_imagem_registro_mensal` AFTER UPDATE ON `funcao_imagem` FOR EACH ROW BEGIN
    DECLARE _img_status INT DEFAULT NULL;
    DECLARE _obs VARCHAR(100) DEFAULT '';

    IF (NEW.status <> OLD.status)
       AND (NEW.status IN ('Em aprovação', 'Finalizado', 'Aprovado com ajustes', 'Aprovado')) THEN

        
        SELECT status_id INTO _img_status
        FROM imagens_cliente_obra
        WHERE idimagens_cliente_obra = NEW.imagem_id
        LIMIT 1;

        IF NEW.funcao_id = 4 THEN
            IF _img_status = 1 THEN
                SET _obs = 'Finalização Parcial';
            ELSE
                SET _obs = 'Finalização Completa';
            END IF;
        ELSE
            SET _obs = '';
        END IF;

        
        IF _obs IS NULL THEN
            SET _obs = '';
        END IF;

        INSERT IGNORE INTO funcao_imagem_registro_mensal (
            funcao_imagem_id,
            colaborador_id,
            imagem_id,
            funcao_id,
            status_registrado,
            observacao,
            data_evento,
            ano,
            mes
        ) VALUES (
            NEW.idfuncao_imagem,
            NEW.colaborador_id,
            NEW.imagem_id,
            NEW.funcao_id,
            NEW.status,
            IFNULL(_obs, ''),
            NOW(),
            YEAR(NOW()),
            MONTH(NOW())
        );
    END IF;
END */;;
DELIMITER ;
