--
-- Table structure for table `imagens_cliente_obra`
--

DROP TABLE IF EXISTS `imagens_cliente_obra`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `imagens_cliente_obra` (
  `idimagens_cliente_obra` int NOT NULL AUTO_INCREMENT,
  `cliente_id` int NOT NULL,
  `obra_id` int NOT NULL,
  `imagem_nome` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `recebimento_arquivos` date DEFAULT NULL,
  `data_inicio` date DEFAULT NULL,
  `prazo` date DEFAULT NULL,
  `tipo_imagem` varchar(55) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `subtipo_imagem` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status_id` int DEFAULT NULL,
  `antecipada` tinyint(1) NOT NULL,
  `dias_trabalhados` int NOT NULL,
  `animacao` tinyint(1) NOT NULL DEFAULT '0',
  `clima` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `substatus_id` int DEFAULT NULL,
  `subtipo_id` int DEFAULT NULL,
  PRIMARY KEY (`idimagens_cliente_obra`),
  KEY `cliente_id` (`cliente_id`),
  KEY `obra_id` (`obra_id`),
  KEY `status_imagem` (`status_id`),
  KEY `substatus_id` (`substatus_id`),
  KEY `fk_imagens_subtipo` (`subtipo_id`),
  CONSTRAINT `fk_imagens_subtipo` FOREIGN KEY (`subtipo_id`) REFERENCES `subtipo_imagem` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `imagens_cliente_obra_ibfk_1` FOREIGN KEY (`cliente_id`) REFERENCES `cliente` (`idcliente`),
  CONSTRAINT `imagens_cliente_obra_ibfk_2` FOREIGN KEY (`obra_id`) REFERENCES `obra` (`idobra`),
  CONSTRAINT `imagens_cliente_obra_ibfk_3` FOREIGN KEY (`substatus_id`) REFERENCES `substatus_imagem` (`id`),
  CONSTRAINT `status_imagem` FOREIGN KEY (`status_id`) REFERENCES `status_imagem` (`idstatus`)
) ENGINE=InnoDB AUTO_INCREMENT=2888 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

