/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `set_status_id` BEFORE INSERT ON `imagens_cliente_obra` FOR EACH ROW BEGIN
    IF NEW.status_id IS NULL THEN

        IF NEW.tipo_imagem = 'Planta Humanizada' THEN
            SET NEW.status_id = 2;
            SET NEW.substatus_id = 7;
        ELSE
            SET NEW.status_id = 1;
            SET NEW.substatus_id = 7;
        END IF;

    END IF;
END */;;
