/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_historico_imagens_update` BEFORE UPDATE ON `imagens_cliente_obra` FOR EACH ROW BEGIN
    
    IF OLD.status_id <> NEW.status_id THEN
        SET NEW.substatus_id = 2;
    END IF;

    
    IF (OLD.status_id <> NEW.status_id) OR (OLD.substatus_id <> NEW.substatus_id) THEN
        INSERT INTO historico_imagens (imagem_id, status_id, substatus_id)
        VALUES (NEW.idimagens_cliente_obra, NEW.status_id, NEW.substatus_id);
    END IF;
END */;;
